-- =====================================================================
--  الأربعون في محبة رب العالمين — جدول جديد
--  التاريخ: 2026-07-17
--  آمن للتشغيل مرات متعددة (IF NOT EXISTS)
--
--  طلب صريح من المالك: "ابحث عن مصادر وجمعها الأربعين في محبة رب العالمين".
--  لم يُعثر على مؤلَّف قائم بعينه بهذا الاسم الدقيق (أقرب عنوان معروف:
--  "الأربعون في عظمة رب العالمين" للشيخ محمد صالح المنجّد — عن "عظمة" لا
--  "محبة"). فبدل اختلاق قائمة من الذاكرة، جُمعت 17 حديثاً (من أصل 40) عبر
--  بحث نصي مباشر في قاعدة بيانات fawazahmed0/hadith-api الكاملة (مرخّصة
--  MIT، نفس المصدر المستخدم فعلاً في صفحة "الكتب الحديثية الكاملة" لهذا
--  الموقع) عن الأحاديث التي تتضمن محبة الله لعبده أو محبة العبد لربه أو
--  صفة من صفاته المتعلقة بالمحبة — كل نص هنا منسوخ حرفياً من المصدر بلا
--  أي تعديل، مع رقم الحديث ومصدره الدقيق. الـ23 حديثاً المتبقية لإكمال
--  الأربعين تحتاج بحثاً إضافياً (قيد التنفيذ).
--
--  قاعدة حاكمة: لا يظهر أي حديث للزوار (review_status='published') حتى
--  يراجعه عالِم شرعي فعلي ويعتمد درجته — نفس نمط week_day_facts.
-- =====================================================================

CREATE TABLE IF NOT EXISTS public.arbaeen_love_of_allah (
  id            uuid PRIMARY KEY DEFAULT gen_random_uuid(),
  order_number  integer,
  title         text NOT NULL,
  hadith_text   text NOT NULL,
  source        text NOT NULL,   -- مثل: صحيح البخاري
  hadith_number text,            -- رقم الحديث في المصدر (ترقيم fawazahmed0/hadith-api)
  grade         text CHECK (grade IN ('صحيح','حسن','ضعيف') OR grade IS NULL),
  verified_by   text,            -- اسم المراجع الشرعي أو الجهة
  review_status text NOT NULL DEFAULT 'draft' CHECK (review_status IN (
                  'draft','in_review','verified','published','rejected'
                )),
  editor_notes  text,
  created_at    timestamptz NOT NULL DEFAULT now(),
  updated_at    timestamptz NOT NULL DEFAULT now()
);

CREATE INDEX IF NOT EXISTS idx_arbaeen_love_status ON public.arbaeen_love_of_allah(review_status, order_number);

ALTER TABLE public.arbaeen_love_of_allah ENABLE ROW LEVEL SECURITY;
DROP POLICY IF EXISTS "arbaeen_love_public_read" ON public.arbaeen_love_of_allah;
CREATE POLICY "arbaeen_love_public_read" ON public.arbaeen_love_of_allah
  FOR SELECT USING (review_status = 'published');
DROP POLICY IF EXISTS "arbaeen_love_admin_all" ON public.arbaeen_love_of_allah;
CREATE POLICY "arbaeen_love_admin_all" ON public.arbaeen_love_of_allah
  FOR ALL USING (is_admin() OR auth.role() = 'service_role')
  WITH CHECK (is_admin() OR auth.role() = 'service_role');

DO $$
BEGIN
  IF EXISTS (SELECT 1 FROM pg_proc WHERE proname = 'set_updated_at') THEN
    DROP TRIGGER IF EXISTS trg_arbaeen_love_updated_at ON public.arbaeen_love_of_allah;
    CREATE TRIGGER trg_arbaeen_love_updated_at
      BEFORE UPDATE ON public.arbaeen_love_of_allah
      FOR EACH ROW EXECUTE FUNCTION public.set_updated_at();
  END IF;
END $$;

-- بذر أولي 17 حديثاً (من 40) — كل نص مسحوب حرفياً من fawazahmed0/hadith-api
-- (مرخّص MIT) — لا اختلاق. الحالة الافتراضية in_review: لا يظهر للزوار
-- حتى مراجعة عالِم شرعي يوثّق درجة كل حديث ويعتمده.
INSERT INTO public.arbaeen_love_of_allah (order_number, title, hadith_text, source, hadith_number, review_status) VALUES
(1, 'حلاوة الإيمان: أن يكون الله ورسوله أحب إليه مما سواهما', 'حَدَّثَنَا مُحَمَّدُ بْنُ الْمُثَنَّى، قَالَ حَدَّثَنَا عَبْدُ الْوَهَّابِ الثَّقَفِيُّ، قَالَ حَدَّثَنَا أَيُّوبُ، عَنْ أَبِي قِلاَبَةَ، عَنْ أَنَسٍ، عَنِ النَّبِيِّ صلى الله عليه وسلم قَالَ ‏"‏ ثَلاَثٌ مَنْ كُنَّ فِيهِ وَجَدَ حَلاَوَةَ الإِيمَانِ أَنْ يَكُونَ اللَّهُ وَرَسُولُهُ أَحَبَّ إِلَيْهِ مِمَّا سِوَاهُمَا، وَأَنْ يُحِبَّ الْمَرْءَ لاَ يُحِبُّهُ إِلاَّ لِلَّهِ، وَأَنْ يَكْرَهَ أَنْ يَعُودَ فِي الْكُفْرِ كَمَا يَكْرَهُ أَنْ يُقْذَفَ فِي النَّارِ ‏"‏‏.‏', 'صحيح البخاري', '16', 'in_review'),
(2, 'أي الأعمال أحب إلى الله؟ الصلاة على وقتها', 'حَدَّثَنَا أَبُو الْوَلِيدِ، هِشَامُ بْنُ عَبْدِ الْمَلِكِ قَالَ حَدَّثَنَا شُعْبَةُ، قَالَ الْوَلِيدُ بْنُ الْعَيْزَارِ أَخْبَرَنِي قَالَ سَمِعْتُ أَبَا عَمْرٍو الشَّيْبَانِيَّ، يَقُولُ حَدَّثَنَا صَاحِبُ، هَذِهِ الدَّارِ وَأَشَارَ إِلَى دَارِ عَبْدِ اللَّهِ قَالَ سَأَلْتُ النَّبِيَّ صلى الله عليه وسلم أَىُّ الْعَمَلِ أَحَبُّ إِلَى اللَّهِ قَالَ ‏"‏ الصَّلاَةُ عَلَى وَقْتِهَا ‏"‏‏.‏ قَالَ ثُمَّ أَىٌّ قَالَ ‏"‏ ثُمَّ بِرُّ الْوَالِدَيْنِ ‏"‏‏.‏ قَالَ ثُمَّ أَىٌّ قَالَ ‏"‏ الْجِهَادُ فِي سَبِيلِ اللَّهِ ‏"‏‏.‏ قَالَ حَدَّثَنِي بِهِنَّ وَلَوِ اسْتَزَدْتُهُ لَزَادَنِي‏.‏', 'صحيح البخاري', '527', 'in_review'),
(3, 'سبعة يظلهم الله في ظله: ورجلان تحابا في الله', 'حَدَّثَنَا مُحَمَّدُ بْنُ بَشَّارٍ، قَالَ حَدَّثَنَا يَحْيَى، عَنْ عُبَيْدِ اللَّهِ، قَالَ حَدَّثَنِي خُبَيْبُ بْنُ عَبْدِ الرَّحْمَنِ، عَنْ حَفْصِ بْنِ عَاصِمٍ، عَنْ أَبِي هُرَيْرَةَ، عَنِ النَّبِيِّ صلى الله عليه وسلم قَالَ ‏"‏ سَبْعَةٌ يُظِلُّهُمُ اللَّهُ فِي ظِلِّهِ يَوْمَ لاَ ظِلَّ إِلاَّ ظِلُّهُ الإِمَامُ الْعَادِلُ، وَشَابٌّ نَشَأَ فِي عِبَادَةِ رَبِّهِ، وَرَجُلٌ قَلْبُهُ مُعَلَّقٌ فِي الْمَسَاجِدِ، وَرَجُلاَنِ تَحَابَّا فِي اللَّهِ اجْتَمَعَا عَلَيْهِ وَتَفَرَّقَا عَلَيْهِ، وَرَجُلٌ طَلَبَتْهُ امْرَأَةٌ ذَاتُ مَنْصِبٍ وَجَمَالٍ فَقَالَ إِنِّي أَخَافُ اللَّهَ، وَرَجُلٌ تَصَدَّقَ أَخْفَى حَتَّى لاَ تَعْلَمَ شِمَالُهُ مَا تُنْفِقُ يَمِينُهُ، وَرَجُلٌ ذَكَرَ اللَّهَ خَالِيًا فَفَاضَتْ عَيْنَاهُ ‏"‏‏.‏', 'صحيح البخاري', '660', 'in_review'),
(4, 'لأعطين الراية رجلاً يحب الله ورسوله ويحبه الله ورسوله', 'حَدَّثَنَا قُتَيْبَةُ بْنُ سَعِيدٍ، حَدَّثَنَا يَعْقُوبُ بْنُ عَبْدِ الرَّحْمَنِ بْنِ مُحَمَّدِ بْنِ عَبْدِ اللَّهِ بْنِ عَبْدِ الْقَارِي، عَنْ أَبِي حَازِمٍ، قَالَ أَخْبَرَنِي سَهْلٌ ـ رضى الله عنه يَعْنِي ابْنَ سَعْدٍ ـ قَالَ قَالَ النَّبِيُّ صلى الله عليه وسلم يَوْمَ خَيْبَرَ ‏"‏ لأُعْطِيَنَّ الرَّايَةَ غَدًا رَجُلاً يَفْتَحُ عَلَى يَدَيْهِ، يُحِبُّ اللَّهَ وَرَسُولَهُ، وَيُحِبُّهُ اللَّهُ وَرَسُولُهُ ‏"‏‏.‏', 'صحيح البخاري', '3009', 'in_review'),
(5, 'المرء مع من أحب', 'حَدَّثَنَا سُلَيْمَانُ بْنُ حَرْبٍ، حَدَّثَنَا حَمَّادُ بْنُ زَيْدٍ، عَنْ ثَابِتٍ، عَنْ أَنَسٍ ـ رضى الله عنه ـ أَنَّ رَجُلاً، سَأَلَ النَّبِيَّ صلى الله عليه وسلم عَنِ السَّاعَةِ، فَقَالَ مَتَى السَّاعَةُ قَالَ ‏"‏ وَمَاذَا أَعْدَدْتَ لَهَا ‏"‏‏.‏ قَالَ لاَ شَىْءَ إِلاَّ أَنِّي أُحِبُّ اللَّهَ وَرَسُولَهُ صلى الله عليه وسلم‏.‏ فَقَالَ ‏"‏ أَنْتَ مَعَ مَنْ أَحْبَبْتَ ‏"‏‏.‏', 'صحيح البخاري', '3688', 'in_review'),
(6, 'إذا أحب الله عبداً نادى جبريل', 'حَدَّثَنَا عَمْرُو بْنُ عَلِيٍّ، حَدَّثَنَا أَبُو عَاصِمٍ، عَنِ ابْنِ جُرَيْجٍ، قَالَ أَخْبَرَنِي مُوسَى بْنُ عُقْبَةَ، عَنْ نَافِعٍ، عَنْ أَبِي هُرَيْرَةَ، عَنِ النَّبِيِّ صلى الله عليه وسلم قَالَ ‏"‏ إِذَا أَحَبَّ اللَّهُ عَبْدًا نَادَى جِبْرِيلَ إِنَّ اللَّهَ يُحِبُّ فُلاَنًا، فَأَحِبَّهُ‏.‏ فَيُحِبُّهُ جِبْرِيلُ، فَيُنَادِي جِبْرِيلُ فِي أَهْلِ السَّمَاءِ إِنَّ اللَّهَ يُحِبُّ فُلاَنًا، فَأَحِبُّوهُ‏.‏ فَيُحِبُّهُ أَهْلُ السَّمَاءِ، ثُمَّ يُوضَعُ لَهُ الْقَبُولُ فِي الأَرْضِ ‏"‏‏.‏', 'صحيح البخاري', '6040', 'in_review'),
(7, 'الله أفرح بتوبة عبده', 'حَدَّثَنَا إِسْحَاقُ، أَخْبَرَنَا حِبَّانُ، حَدَّثَنَا هَمَّامٌ، حَدَّثَنَا قَتَادَةُ، حَدَّثَنَا أَنَسُ بْنُ مَالِكٍ، عَنِ النَّبِيِّ صلى الله عليه وسلم‏.‏ وَحَدَّثَنَا هُدْبَةُ، حَدَّثَنَا هَمَّامٌ، حَدَّثَنَا قَتَادَةُ، عَنْ أَنَسٍ ـ رضى الله عنه ـ قَالَ قَالَ رَسُولُ اللَّهِ صلى الله عليه وسلم ‏"‏ اللَّهُ أَفْرَحُ بِتَوْبَةِ عَبْدِهِ مِنْ أَحَدِكُمْ سَقَطَ عَلَى بَعِيرِهِ، وَقَدْ أَضَلَّهُ فِي أَرْضِ فَلاَةٍ ‏"‏‏.‏', 'صحيح البخاري', '6309', 'in_review'),
(8, 'أحب الأعمال إلى الله أدومها وإن قل', 'حَدَّثَنِي مُحَمَّدُ بْنُ عَرْعَرَةَ، حَدَّثَنَا شُعْبَةُ، عَنْ سَعْدِ بْنِ إِبْرَاهِيمَ، عَنْ أَبِي سَلَمَةَ، عَنْ عَائِشَةَ ـ رضى الله عنها ـ أَنَّهَا قَالَتْ سُئِلَ النَّبِيُّ صلى الله عليه وسلم أَىُّ الأَعْمَالِ أَحَبُّ إِلَى اللَّهِ قَالَ ‏"‏ أَدْوَمُهَا وَإِنْ قَلَّ ‏"‏‏.‏ وَقَالَ ‏"‏ اكْلَفُوا مِنَ الأَعْمَالِ مَا تُطِيقُونَ ‏"‏‏.‏', 'صحيح البخاري', '6465', 'in_review'),
(9, 'من عادى لي ولياً فقد آذنته بالحرب — حديث قدسي', 'حَدَّثَنِي مُحَمَّدُ بْنُ عُثْمَانَ، حَدَّثَنَا خَالِدُ بْنُ مَخْلَدٍ، حَدَّثَنَا سُلَيْمَانُ بْنُ بِلاَلٍ، حَدَّثَنِي شَرِيكُ بْنُ عَبْدِ اللَّهِ بْنِ أَبِي نَمِرٍ، عَنْ عَطَاءٍ، عَنْ أَبِي هُرَيْرَةَ، قَالَ قَالَ رَسُولُ اللَّهِ صلى الله عليه وسلم ‏"‏ إِنَّ اللَّهَ قَالَ مَنْ عَادَى لِي وَلِيًّا فَقَدْ آذَنْتُهُ بِالْحَرْبِ، وَمَا تَقَرَّبَ إِلَىَّ عَبْدِي بِشَىْءٍ أَحَبَّ إِلَىَّ مِمَّا افْتَرَضْتُ عَلَيْهِ، وَمَا يَزَالُ عَبْدِي يَتَقَرَّبُ إِلَىَّ بِالنَّوَافِلِ حَتَّى أُحِبَّهُ، فَإِذَا أَحْبَبْتُهُ كُنْتُ سَمْعَهُ الَّذِي يَسْمَعُ بِهِ، وَبَصَرَهُ الَّذِي يُبْصِرُ بِهِ، وَيَدَهُ الَّتِي يَبْطُشُ بِهَا وَرِجْلَهُ الَّتِي يَمْشِي بِهَا، وَإِنْ سَأَلَنِي لأُعْطِيَنَّهُ، وَلَئِنِ اسْتَعَاذَنِي لأُعِيذَنَّهُ، وَمَا تَرَدَّدْتُ عَنْ شَىْءٍ أَنَا فَاعِلُهُ تَرَدُّدِي عَنْ نَفْسِ الْمُؤْمِنِ، يَكْرَهُ الْمَوْتَ وَأَنَا أَكْرَهُ مَسَاءَتَهُ ‏"‏‏.‏', 'صحيح البخاري', '6502', 'in_review'),
(10, 'من أحب لقاء الله أحب الله لقاءه', 'حَدَّثَنَا حَجَّاجٌ، حَدَّثَنَا هَمَّامٌ، حَدَّثَنَا قَتَادَةُ، عَنْ أَنَسٍ، عَنْ عُبَادَةَ بْنِ الصَّامِتِ، عَنِ النَّبِيِّ صلى الله عليه وسلم قَالَ ‏"‏ مَنْ أَحَبَّ لِقَاءَ اللَّهِ أَحَبَّ اللَّهُ لِقَاءَهُ، وَمَنْ كَرِهَ لِقَاءَ اللَّهِ كَرِهَ اللَّهُ لِقَاءَهُ ‏"‏‏.‏ قَالَتْ عَائِشَةُ أَوْ بَعْضُ أَزْوَاجِهِ إِنَّا لَنَكْرَهُ الْمَوْتَ‏.‏ قَالَ ‏"‏ لَيْسَ ذَاكَ، وَلَكِنَّ الْمُؤْمِنَ إِذَا حَضَرَهُ الْمَوْتُ بُشِّرَ بِرِضْوَانِ اللَّهِ وَكَرَامَتِهِ، فَلَيْسَ شَىْءٌ أَحَبَّ إِلَيْهِ مِمَّا أَمَامَهُ، فَأَحَبَّ لِقَاءَ اللَّهِ وَأَحَبَّ اللَّهُ لِقَاءَهُ‏.‏', 'صحيح البخاري', '6507', 'in_review'),
(11, 'لا تؤمنوا حتى تحابوا', 'حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ، حَدَّثَنَا أَبُو مُعَاوِيَةَ، وَوَكِيعٌ، عَنِ الأَعْمَشِ، عَنْ أَبِي صَالِحٍ، عَنْ أَبِي هُرَيْرَةَ، قَالَ قَالَ رَسُولُ اللَّهِ صلى الله عليه وسلم ‏"‏ لاَ تَدْخُلُونَ الْجَنَّةَ حَتَّى تُؤْمِنُوا وَلاَ تُؤْمِنُوا حَتَّى تَحَابُّوا ‏.‏ أَوَلاَ أَدُلُّكُمْ عَلَى شَىْءٍ إِذَا فَعَلْتُمُوهُ تَحَابَبْتُمْ أَفْشُوا السَّلاَمَ بَيْنَكُمْ ‏"‏ ‏.‏', 'صحيح مسلم', '194', 'in_review'),
(12, 'إن الله جميل يحب الجمال', 'وَحَدَّثَنَا مُحَمَّدُ بْنُ الْمُثَنَّى، وَمُحَمَّدُ بْنُ بَشَّارٍ، وَإِبْرَاهِيمُ بْنُ دِينَارٍ، جَمِيعًا عَنْ يَحْيَى بْنِ حَمَّادٍ، - قَالَ ابْنُ الْمُثَنَّى حَدَّثَنِي يَحْيَى بْنُ حَمَّادٍ، - أَخْبَرَنَا شُعْبَةُ، عَنْ أَبَانَ بْنِ تَغْلِبَ، عَنْ فُضَيْلٍ الْفُقَيْمِيِّ، عَنْ إِبْرَاهِيمَ النَّخَعِيِّ، عَنْ عَلْقَمَةَ، عَنْ عَبْدِ اللَّهِ بْنِ مَسْعُودٍ، عَنِ النَّبِيِّ صلى الله عليه وسلم قَالَ ‏"‏ لاَ يَدْخُلُ الْجَنَّةَ مَنْ كَانَ فِي قَلْبِهِ مِثْقَالُ ذَرَّةٍ مِنْ كِبْرٍ ‏"‏ ‏.‏ قَالَ رَجُلٌ إِنَّ الرَّجُلَ يُحِبُّ أَنْ يَكُونَ ثَوْبُهُ حَسَنًا وَنَعْلُهُ حَسَنَةً ‏.‏ قَالَ ‏"‏ إِنَّ اللَّهَ جَمِيلٌ يُحِبُّ الْجَمَالَ الْكِبْرُ بَطَرُ الْحَقِّ وَغَمْطُ النَّاسِ ‏"‏ ‏.‏', 'صحيح مسلم', '265', 'in_review'),
(13, 'أين المتحابون بجلالي؟ اليوم أظلهم في ظلي', 'حَدَّثَنَا قُتَيْبَةُ بْنُ سَعِيدٍ، عَنْ مَالِكِ بْنِ أَنَسٍ، فِيمَا قُرِئَ عَلَيْهِ عَنْ عَبْدِ اللَّهِ بْنِ عَبْدِ، الرَّحْمَنِ بْنِ مَعْمَرٍ عَنْ أَبِي الْحُبَابِ، سَعِيدِ بْنِ يَسَارٍ عَنْ أَبِي هُرَيْرَةَ، قَالَ قَالَ رَسُولُ اللَّهِ صلى الله عليه وسلم ‏"‏ إِنَّ اللَّهَ يَقُولُ يَوْمَ الْقِيَامَةِ أَيْنَ الْمُتَحَابُّونَ بِجَلاَلِي الْيَوْمَ أُظِلُّهُمْ فِي ظِلِّي يَوْمَ لاَ ظِلَّ إِلاَّ ظِلِّي ‏"‏ ‏.‏', 'صحيح مسلم', '6548', 'in_review'),
(14, 'المؤمن القوي خير وأحب إلى الله من المؤمن الضعيف', 'حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ، وَابْنُ، نُمَيْرٍ قَالاَ حَدَّثَنَا عَبْدُ اللَّهِ بْنُ إِدْرِيسَ، عَنْ رَبِيعَةَ بْنِ عُثْمَانَ، عَنْ مُحَمَّدِ بْنِ يَحْيَى بْنِ حَبَّانَ، عَنِ الأَعْرَجِ، عَنْ أَبِي هُرَيْرَةَ، قَالَ قَالَ رَسُولُ اللَّهِ صلى الله عليه وسلم ‏"‏ الْمُؤْمِنُ الْقَوِيُّ خَيْرٌ وَأَحَبُّ إِلَى اللَّهِ مِنَ الْمُؤْمِنِ الضَّعِيفِ، وَفِي كُلٍّ خَيْرٌ، احْرِصْ عَلَى مَا يَنْفَعُكَ، وَاسْتَعِنْ بِاللَّهِ وَلاَ تَعْجِزْ ‏"‏ ‏.‏', 'صحيح مسلم', '6774', 'in_review'),
(15, 'إذا أحب الله عبداً حماه الدنيا', 'حَدَّثَنَا مُحَمَّدُ بْنُ يَحْيَى، قال حَدَّثَنَا إِسْحَاقُ بْنُ مُحَمَّدٍ الْفَرْوِيُّ، قال حَدَّثَنَا إِسْمَاعِيلُ بْنُ جَعْفَرٍ، عَنْ عُمَارَةَ بْنِ غَزِيَّةَ، عَنْ عَاصِمِ بْنِ عُمَرَ بْنِ قَتَادَةَ، عَنْ مَحْمُودِ بْنِ لَبِيدٍ، عَنْ قَتَادَةَ بْنِ النُّعْمَانِ، أَنَّ رَسُولَ اللَّهِ صلى الله عليه وسلم قَالَ ‏"‏ إِذَا أَحَبَّ اللَّهُ عَبْدًا حَمَاهُ الدُّنْيَا كَمَا يَظَلُّ أَحَدُكُمْ يَحْمِي مَرِيضَهُ الْمَاءَ ‏"‏ ‏.‏', 'جامع الترمذي', '2036', 'in_review'),
(16, 'دعاء داود عليه السلام: اللهم إني أسألك حبك', 'حَدَّثَنَا أَبُو كُرَيْبٍ، حَدَّثَنَا مُحَمَّدُ بْنُ فُضَيْلٍ، عَنْ مُحَمَّدِ بْنِ سَعْدٍ الأَنْصَارِيِّ، عَنْ عَبْدِ اللَّهِ بْنِ رَبِيعَةَ الدِّمَشْقِيِّ، حَدَّثَنَا عَائِذُ اللَّهِ أَبُو إِدْرِيسَ الْخَوْلاَنِيُّ، عَنْ أَبِي الدَّرْدَاءِ، قَالَ قَالَ رَسُولُ اللَّهِ صلى الله عليه وسلم ‏"‏ كَانَ مِنْ دُعَاءِ دَاوُدَ يَقُولُ اللَّهُمَّ إِنِّي أَسْأَلُكَ حُبَّكَ وَحُبَّ مَنْ يُحِبُّكَ وَالْعَمَلَ الَّذِي يُبَلِّغُنِي حُبَّكَ اللَّهُمَّ اجْعَلْ حُبَّكَ أَحَبَّ إِلَىَّ مِنْ نَفْسِي وَأَهْلِي وَمِنَ الْمَاءِ الْبَارِدِ ‏"‏ ‏.‏', 'جامع الترمذي', '3490', 'in_review'),
(17, 'إن الله رفيق يحب الرفق في الأمر كله', 'حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ، حَدَّثَنَا مُحَمَّدُ بْنُ مُصْعَبٍ، عَنِ الأَوْزَاعِيِّ، ح وَحَدَّثَنَا هِشَامُ بْنُ عَمَّارٍ، وَعَبْدُ الرَّحْمَنِ بْنُ إِبْرَاهِيمَ، قَالاَ حَدَّثَنَا الْوَلِيدُ بْنُ مُسْلِمٍ، حَدَّثَنَا الأَوْزَاعِيُّ، عَنِ الزُّهْرِيِّ، عَنْ عُرْوَةَ، عَنْ عَائِشَةَ، عَنِ النَّبِيِّ ـ صلى الله عليه وسلم ـ قَالَ ‏"‏ إِنَّ اللَّهَ رَفِيقٌ يُحِبُّ الرِّفْقَ فِي الأَمْرِ كُلِّهِ ‏"‏ ‏.‏', 'سنن ابن ماجه', '3689', 'in_review');
